// Command routinglint runs the FEAT-006 routing-cleanup analyzer
// (ddx-653f6ac9). It fails if any of the compensating-routing
// helpers retired by ddx-3bd7396a have been reintroduced.
//
// Usage:
//
//	go run ./tools/lint/routinglint/cmd/routinglint ./...
package main

import (
	"github.com/DocumentDrivenDX/ddx/tools/lint/routinglint"
	"golang.org/x/tools/go/analysis/singlechecker"
)

func main() {
	singlechecker.Main(routinglint.Analyzer)
}

// Package routinglint implements the FEAT-006 routing-cleanup lint
// rule that mechanically forbids reintroduction of DDx-side
// "compensating routing" logic that was deleted with prejudice in
// ddx-3bd7396a.
//
// The parent epic ddx-fdd3ea36 §AC#7 says:
//
//	"Search DDx for code that re-implements upstream routing
//	concerns: allow-list checks, exact-pin filtering,
//	profile-to-preference mapping, provider cost scoring. Must be
//	absent on the default path. ... Dead-code detector run in CI
//	catches orphans."
//
// Parent-epic AC#7 originally expected the helpers to remain present,
// reachable only via --escalate. The follow-up bead ddx-3bd7396a
// instead deleted them entirely, so this analyzer enforces the
// stricter invariant: the listed compensating-routing identifiers and
// flag literals must not reappear anywhere in cli/ Go source. If they
// do, the cleanup has regressed and CI fails.
//
// Forbidden identifiers (exact name match):
//
//	ResolveProfileLadder, ResolveTierModelRef, AdaptiveMinTier,
//	workersByHarness, ResolveProfileLadderCallCount.
//
// Forbidden string literals (anywhere in cli/ Go source):
//
//	"--escalate", "--override-model",
//	"profile_ladders", "model_overrides",
//	"agent.routing.profile_ladders",
//	"agent.routing.model_overrides".
//
// String-literal occurrences inside this analyzer's own package and
// inside testdata fixtures are exempt.
//
// A specific occurrence may be intentionally exempted (e.g. the
// migration code that rejects a config containing
// agent.routing.profile_ladders has to name the literal key) by
// adding a
//
//	// routinglint:legacy-rejection reason="..."
//
// comment on the same line as the offending node, or on a comment
// line directly above it. The reason= clause must be present and
// non-empty.
package routinglint

import (
	"go/ast"
	"go/token"
	"regexp"
	"strings"

	"golang.org/x/tools/go/analysis"
	"golang.org/x/tools/go/analysis/passes/inspect"
	"golang.org/x/tools/go/ast/inspector"
)

const exemptionAnnotation = "routinglint:legacy-rejection"

var exemptionRE = regexp.MustCompile(`routinglint:legacy-rejection\s+reason="[^"]+"`)

// Analyzer is the FEAT-006 routing-cleanup analyzer.
var Analyzer = &analysis.Analyzer{
	Name:     "routinglint",
	Doc:      "flags reintroduction of compensating DDx-side routing helpers and flags retired by FEAT-006 / ddx-3bd7396a",
	Requires: []*analysis.Analyzer{inspect.Analyzer},
	Run:      run,
}

// forbiddenIdents is the closed list of compensating-routing
// identifiers retired by ddx-3bd7396a. Reintroduction is a CI failure.
var forbiddenIdents = map[string]string{
	"BuiltinCatalog":                "DDx-side routing catalog retired by ddx-cd641910",
	"DefaultModelCatalogPath":       "DDx-side model catalog path retired by ddx-cd641910",
	"LoadModelCatalogYAML":          "DDx-side model catalog loader retired by ddx-cd641910",
	"ApplyModelCatalogYAML":         "DDx-side model catalog overlay retired by ddx-cd641910",
	"DefaultModelCatalogYAML":       "DDx-side model catalog seed retired by ddx-cd641910",
	"CheckDeprecatedPin":            "DDx-side catalog pin check retired by ddx-cd641910",
	"ResolveProfileLadder":          "tier-ladder resolver retired by ddx-3bd7396a — DDx must not re-implement profile-to-preference mapping",
	"ResolveTierModelRef":           "tier-model resolver retired by ddx-3bd7396a — DDx must not re-implement exact-pin filtering",
	"ResolveProfileLadderCallCount": "test seam for the retired tier-ladder resolver — also retired by ddx-3bd7396a",
	"AdaptiveMinTier":               "adaptive-min-tier promotion logic retired by ddx-3bd7396a",
	"workersByHarness":              "escalation worker grouping helper retired by ddx-3bd7396a",
	"queueByHarness":                "using harness as a queue-selection criterion violates the passthrough envelope contract (ddx-20047dd5)",
	"retryByPassthrough":            "using passthrough values in retry policy violates the passthrough envelope contract (ddx-20047dd5)",
	"endpointByPassthrough":         "using passthrough values in endpoint selection violates the passthrough envelope contract (ddx-20047dd5)",
	"catalogThresholdForHarness":    "using harness in catalog threshold evaluation violates the passthrough envelope contract (ddx-20047dd5)",
	"ResolveModelTier":              "DDx-side model tier resolution retired by ddx-ef81fa60",
	"resolveStrongSplitterMinPower": "DDx-side strong-power trick retired by ddx-ef81fa60",
	"isStrongPowerUnsatisfiedError": "DDx-side routing error substring retry retired by ddx-ef81fa60",
	"isSmartRouteUnavailableError":  "DDx-side routing error substring retry retired by ddx-ef81fa60",
}

// forbiddenLiterals is the closed list of CLI flag and config-key
// strings retired by ddx-3bd7396a. They must not appear as Go string
// literals anywhere in cli/.
var forbiddenLiterals = map[string]string{
	"--escalate":                    "--escalate flag retired by ddx-3bd7396a — escalation is not a DDx-side concern",
	"--override-model":              "--override-model flag retired by ddx-3bd7396a — model overrides go through --model on the default path",
	"profile_ladders":               "agent.routing.profile_ladders config key retired by ddx-3bd7396a",
	"model_overrides":               "agent.routing.model_overrides config key retired by ddx-3bd7396a",
	"agent.routing.profile_ladders": "agent.routing.profile_ladders config key retired by ddx-3bd7396a",
	"agent.routing.model_overrides": "agent.routing.model_overrides config key retired by ddx-3bd7396a",
}

// selfPkgFragments lists path fragments that mark this analyzer's own
// package or its testdata fixtures. Diagnostics from those packages
// are suppressed because the closed-list constants above legitimately
// embed every forbidden token.
var selfPkgFragments = []string{
	"/tools/lint/routinglint",
	"tools/lint/routinglint",
}

func inSelfPkg(pass *analysis.Pass) bool {
	if pass.Pkg == nil {
		return false
	}
	p := pass.Pkg.Path()
	for _, f := range selfPkgFragments {
		if strings.Contains(p, f) {
			return true
		}
	}
	return false
}

func run(pass *analysis.Pass) (interface{}, error) {
	if inSelfPkg(pass) {
		return nil, nil
	}

	insp := pass.ResultOf[inspect.Analyzer].(*inspector.Inspector)

	// Build a per-file index of lines that carry an exemption
	// annotation, either as an inline comment on the same line or as
	// a stand-alone comment line directly above. The annotation
	// covers the line it sits on plus the line immediately following.
	exempted := make(map[token.Position]bool)
	for _, f := range pass.Files {
		for _, cg := range f.Comments {
			for _, c := range cg.List {
				if !strings.Contains(c.Text, exemptionAnnotation) {
					continue
				}
				if !exemptionRE.MatchString(c.Text) {
					pass.Report(analysis.Diagnostic{
						Pos:     c.Pos(),
						Message: `routinglint: ` + exemptionAnnotation + ` annotation is missing a non-empty reason="..." clause`,
					})
					continue
				}
				cp := pass.Fset.Position(c.Pos())
				exempted[token.Position{Filename: cp.Filename, Line: cp.Line}] = true
				exempted[token.Position{Filename: cp.Filename, Line: cp.Line + 1}] = true
			}
		}
	}

	isExempt := func(pos token.Pos) bool {
		p := pass.Fset.Position(pos)
		return exempted[token.Position{Filename: p.Filename, Line: p.Line}]
	}

	report := func(pos token.Pos, msg string) {
		if isExempt(pos) {
			return
		}
		pass.Report(analysis.Diagnostic{Pos: pos, Message: msg})
	}

	// Forbidden identifiers — flag at every occurrence, both
	// declarations and references. Matching is exact on Ident.Name so
	// substrings inside larger identifiers (e.g. the test name
	// TestExecuteLoopLocalRejectsProfileLadders) do not trip the lint.
	insp.Preorder([]ast.Node{(*ast.Ident)(nil)}, func(n ast.Node) {
		id := n.(*ast.Ident)
		if reason, ok := forbiddenIdents[id.Name]; ok {
			report(id.Pos(), "routinglint: forbidden identifier "+id.Name+" — "+reason)
		}
	})

	// Forbidden string literals — flag the literal node itself.
	insp.Preorder([]ast.Node{(*ast.BasicLit)(nil)}, func(n ast.Node) {
		lit := n.(*ast.BasicLit)
		if lit.Kind != token.STRING {
			return
		}
		// Trim surrounding quote/backtick so we compare raw value.
		s := lit.Value
		if len(s) >= 2 && (s[0] == '"' || s[0] == '`') {
			s = s[1 : len(s)-1]
		}
		if reason, ok := forbiddenLiterals[s]; ok {
			report(lit.Pos(), "routinglint: forbidden string literal "+lit.Value+" — "+reason)
		}
	})

	return nil, nil
}

// Package runtimelint implements the SD-024 Stage 4 structural lint
// rule that mechanically forbids the durable-knob fields on *Runtime
// structs and the reintroduction of the legacy *Options types.
//
// Three patterns flagged:
//
//  1. Forbidden field name on a *Runtime struct declared in
//     cli/internal/agent/. Forbidden names are a closed list (see
//     forbiddenRuntimeFields below); allowed runtime-intent fields
//     such as NoReview, PollInterval, SessionLogDirOverride are not
//     on the list. Per TD-024 §Lint rule, only struct types whose
//     name ends in "Runtime" are scanned, to avoid false-positives on
//     result/status/event types in cli/internal/agent/types.go.
//
//  2. Composite literal Xxx{...} where Xxx is one of the legacy
//     options types (ExecuteBeadLoopOptions, RunOptions,
//     ExecuteBeadOptions, CompareOptions, QuorumOptions) anywhere in
//     the repository.
//
//  3. Function declaration in cli/internal/agent/ whose signature
//     includes a parameter typed as one of the legacy options types
//     named in pattern 2.
//
// Closed lists are maintained as Go constants — adding a new durable
// knob to *Config requires adding its name to forbiddenRuntimeFields.
package runtimelint

import (
	"go/ast"
	"go/token"
	"go/types"
	"strings"

	"golang.org/x/tools/go/analysis"
	"golang.org/x/tools/go/analysis/passes/inspect"
	"golang.org/x/tools/go/ast/inspector"
)

// Analyzer is the SD-024 Stage 4 structural analyzer.
var Analyzer = &analysis.Analyzer{
	Name:     "runtimelint",
	Doc:      "flags durable-knob fields on *Runtime structs and reintroductions of legacy *Options types per SD-024 §Stage 4 / TD-024 §Lint rule",
	Requires: []*analysis.Analyzer{inspect.Analyzer},
	Run:      run,
}

// forbiddenRuntimeFields is the closed list of durable-knob field
// names that must not appear on *Runtime structs declared in
// cli/internal/agent/. Maintained as a constant per TD-024 §Lint rule.
var forbiddenRuntimeFields = map[string]bool{
	"Harness":                 true,
	"Model":                   true,
	"Provider":                true,
	"ModelRef":                true,
	"Profile":                 true,
	"Effort":                  true,
	"Permissions":             true,
	"Timeout":                 true,
	"WallClock":               true,
	"ContextBudget":           true,
	"MinTier":                 true,
	"MaxTier":                 true,
	"Assignee":                true,
	"ReviewMaxRetries":        true,
	"NoProgressCooldown":      true,
	"MaxNoChangesBeforeClose": true,
	"HeartbeatInterval":       true,
	"SessionLogDir":           true, // durable variant; SessionLogDirOverride is allowed
	"MirrorCfg":               true,
	"Models":                  true,
	"ReasoningLevels":         true,
	"Endpoints":               true,
	"ProfileLadders":          true,
	"ModelOverrides":          true,
	"PerHarness":              true,
}

// legacyOptionsTypes is the closed list of legacy options type names
// that must not be reintroduced (composite literal) or accepted as a
// function parameter in cli/internal/agent/.
var legacyOptionsTypes = map[string]bool{
	"ExecuteBeadLoopOptions": true,
	"RunOptions":             true,
	"ExecuteBeadOptions":     true,
	"CompareOptions":         true,
	"QuorumOptions":          true,
}

// agentPkgSuffixes lists the package import-path suffixes considered
// the cli/internal/agent/ package for scoping rules 1 and 3.
var agentPkgSuffixes = []string{
	"/internal/agent",
	"internal/agent",
	"agent", // permissive: testdata stub uses bare "agent"
}

func pkgPathHasSuffix(p string, suffixes []string) bool {
	for _, s := range suffixes {
		if p == s || strings.HasSuffix(p, s) {
			return true
		}
	}
	return false
}

// inAgentPkg reports whether the analyzer pass is operating on a
// package whose path is cli/internal/agent/ (or a testdata stub).
func inAgentPkg(pass *analysis.Pass) bool {
	if pass.Pkg == nil {
		return false
	}
	return pkgPathHasSuffix(pass.Pkg.Path(), agentPkgSuffixes)
}

func run(pass *analysis.Pass) (interface{}, error) {
	insp := pass.ResultOf[inspect.Analyzer].(*inspector.Inspector)

	// Skip the analyzer's own package.
	if pass.Pkg != nil {
		path := pass.Pkg.Path()
		if strings.HasSuffix(path, "/tools/lint/runtimelint") ||
			strings.Contains(path, "/tools/lint/runtimelint/") {
			return nil, nil
		}
	}

	report := func(pos token.Pos, msg string) {
		pass.Report(analysis.Diagnostic{Pos: pos, Message: msg})
	}

	// Pattern 1: forbidden field on *Runtime struct in agent pkg.
	if inAgentPkg(pass) {
		insp.Preorder([]ast.Node{(*ast.TypeSpec)(nil)}, func(n ast.Node) {
			ts := n.(*ast.TypeSpec)
			checkRuntimeStruct(ts, report)
		})
	}

	// Pattern 2: composite literal of legacy options type (anywhere).
	insp.Preorder([]ast.Node{(*ast.CompositeLit)(nil)}, func(n ast.Node) {
		cl := n.(*ast.CompositeLit)
		checkLegacyComposite(pass, cl, report)
	})

	// Pattern 3: function param typed as legacy options (agent pkg).
	// Walk only FuncDecl — function-typed values inside the package are
	// not the surface we care about; the rule targets declared
	// signatures.
	if inAgentPkg(pass) {
		insp.Preorder([]ast.Node{(*ast.FuncDecl)(nil)}, func(n ast.Node) {
			fd := n.(*ast.FuncDecl)
			if fd.Type != nil {
				checkLegacyParam(pass, fd.Type, report)
			}
		})
	}

	return nil, nil
}

// --- Pattern 1: forbidden field on *Runtime struct ------------------------

func checkRuntimeStruct(ts *ast.TypeSpec, report func(token.Pos, string)) {
	if ts.Name == nil || !strings.HasSuffix(ts.Name.Name, "Runtime") {
		return
	}
	st, ok := ts.Type.(*ast.StructType)
	if !ok || st.Fields == nil {
		return
	}
	for _, f := range st.Fields.List {
		for _, name := range f.Names {
			if forbiddenRuntimeFields[name.Name] {
				report(name.Pos(),
					"runtimelint: forbidden durable-knob field "+name.Name+" on *Runtime struct "+ts.Name.Name+" — durable knobs belong on config.ResolvedConfig, not on the runtime struct (SD-024 §Runtime structs / TD-024 §Lint rule)")
			}
		}
	}
}

// --- Pattern 2: composite literal of legacy options type ------------------

func checkLegacyComposite(pass *analysis.Pass, cl *ast.CompositeLit, report func(token.Pos, string)) {
	t := pass.TypesInfo.TypeOf(cl)
	if t == nil {
		return
	}
	if ptr, ok := t.(*types.Pointer); ok {
		t = ptr.Elem()
	}
	named, ok := t.(*types.Named)
	if !ok {
		return
	}
	obj := named.Obj()
	if obj == nil {
		return
	}
	if !legacyOptionsTypes[obj.Name()] {
		return
	}
	// Scope to types declared in cli/internal/agent/ — avoids false-
	// positives if some unrelated package happens to use the same name.
	if obj.Pkg() == nil || !pkgPathHasSuffix(obj.Pkg().Path(), agentPkgSuffixes) {
		return
	}
	report(cl.Pos(),
		"runtimelint: composite literal of legacy options type "+obj.Name()+" — these types are retired; use the *Runtime + ResolvedConfig pair instead (SD-024 §Stage 4 / TD-024 §Lint rule)")
}

// --- Pattern 3: function param typed as legacy options --------------------

func checkLegacyParam(pass *analysis.Pass, ft *ast.FuncType, report func(token.Pos, string)) {
	if ft.Params == nil {
		return
	}
	for _, field := range ft.Params.List {
		if isLegacyOptionsType(pass, field.Type) {
			report(field.Pos(),
				"runtimelint: function parameter typed as legacy options — these types are retired; use a *Runtime parameter plus a config.ResolvedConfig (SD-024 §Stage 4 / TD-024 §Lint rule)")
		}
	}
}

func isLegacyOptionsType(pass *analysis.Pass, e ast.Expr) bool {
	t := pass.TypesInfo.TypeOf(e)
	if t == nil {
		return false
	}
	if ptr, ok := t.(*types.Pointer); ok {
		t = ptr.Elem()
	}
	named, ok := t.(*types.Named)
	if !ok {
		return false
	}
	obj := named.Obj()
	if obj == nil {
		return false
	}

